import javafx.application.Application;
import javafx.geometry.Insets;
import javafx.geometry.Pos;
import javafx.scene.Scene;
import javafx.scene.control.*;
import javafx.scene.layout.VBox;
import javafx.stage.Stage;

public class EventHandlingExample extends Application {
    @Override
    public void start(Stage primaryStage) {
        VBox root = new VBox(15);
        root.setPadding(new Insets(20));
        root.setAlignment(Pos.CENTER);

        Label resultLabel = new Label("Waiting for action...");
        resultLabel.setStyle("-fx-font-size: 16px;");

        // 1. Button click event
        Button button = new Button("Click Me!");
        button.setOnAction(e -> {
            resultLabel.setText("Button clicked!");
            resultLabel.setStyle("-fx-text-fill: green; -fx-font-weight: bold;");
        });

        // 2. TextField events
        TextField textField = new TextField();
        textField.setPromptText("Type something...");
        textField.setMaxWidth(200);

        // Key press event
        textField.setOnKeyPressed(e -> {
            resultLabel.setText("Key pressed: " + e.getCode());
        });

        // Enter key event
        textField.setOnAction(e -> {
            String text = textField.getText();
            resultLabel.setText("Entered: " + text);
        });

        // 3. CheckBox event
        CheckBox checkBox = new CheckBox("Enable feature");
        checkBox.setOnAction(e -> {
            if (checkBox.isSelected()) {
                resultLabel.setText("Feature ENABLED");
            } else {
                resultLabel.setText("Feature DISABLED");
            }
        });

        // 4. RadioButton events
        ToggleGroup radioGroup = new ToggleGroup();
        RadioButton radio1 = new RadioButton("Option A");
        RadioButton radio2 = new RadioButton("Option B");
        RadioButton radio3 = new RadioButton("Option C");
        radio1.setToggleGroup(radioGroup);
        radio2.setToggleGroup(radioGroup);
        radio3.setToggleGroup(radioGroup);

        radioGroup.selectedToggleProperty().addListener((obs, oldVal, newVal) -> {
            if (newVal != null) {
                RadioButton selected = (RadioButton) newVal;
                resultLabel.setText("Selected: " + selected.getText());
            }
        });

        VBox radioBox = new VBox(5);
        radioBox.getChildren().addAll(radio1, radio2, radio3);

        // 5. ComboBox event
        ComboBox<String> comboBox = new ComboBox<>();
        comboBox.getItems().addAll("Item 1", "Item 2", "Item 3");
        comboBox.setValue("Select...");

        comboBox.setOnAction(e -> {
            String selected = comboBox.getValue();
            resultLabel.setText("ComboBox selected: " + selected);
        });

        // 6. ListView event
        ListView<String> listView = new ListView<>();
        listView.getItems().addAll("Apple", "Banana", "Orange", "Grape");
        listView.setMaxWidth(150);
        listView.setPrefHeight(100);

        listView.getSelectionModel().selectedItemProperty().addListener((obs, oldVal, newVal) -> {
            if (newVal != null) {
                resultLabel.setText("Selected fruit: " + newVal);
            }
        });

        // 7. Slider event
        Slider slider = new Slider(0, 100, 50);
        slider.setShowTickLabels(true);
        slider.setMaxWidth(300);

        slider.valueProperty().addListener((obs, oldVal, newVal) -> {
            resultLabel.setText("Slider value: " + String.format("%.0f", newVal.doubleValue()));
        });

        // 8. Clear button
        Button clearBtn = new Button("Clear");
        clearBtn.setOnAction(e -> {
            resultLabel.setText("Cleared!");
            textField.clear();
            comboBox.setValue("Select...");
            listView.getSelectionModel().clearSelection();
            slider.setValue(50);
        });

        root.getChildren().addAll(
            resultLabel,
            button,
            textField,
            checkBox,
            radioBox,
            comboBox,
            listView,
            slider,
            clearBtn
        );

        Scene scene = new Scene(root, 500, 600);

        primaryStage.setTitle("Event Handling");
        primaryStage.setScene(scene);
        primaryStage.show();
    }

    public static void main(String[] args) {
        launch(args);
    }
}

